import { ethers } from "ethers";

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function balanceOf(address owner) external view returns (uint256)",
  "function decimals() external view returns (uint8)",
  "function symbol() external view returns (string)"
];

const DEX_ROUTER_ABI = [
  "function getAmountsOut(uint256 amountIn, address[] calldata path) external view returns (uint256[] memory amounts)",
  "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external returns (uint256[] memory amounts)"
];

const MAX_UINT256 = ethers.MaxUint256;

export class TokenSwapDApp {
  constructor({
    provider,
    signer,
    routerAddress,
    defaultSlippageBps = 50,
    defaultDeadlineSeconds = 60 * 20
  }) {
    if (!provider) throw new Error("provider is required");
    if (!signer) throw new Error("signer is required");
    if (!routerAddress) throw new Error("routerAddress is required");

    this.provider = provider;
    this.signer = signer;
    this.routerAddress = routerAddress;
    this.router = new ethers.Contract(routerAddress, DEX_ROUTER_ABI, signer);
    this.defaultSlippageBps = defaultSlippageBps;
    this.defaultDeadlineSeconds = defaultDeadlineSeconds;
  }

  getTokenContract(tokenAddress, withSigner = true) {
    return new ethers.Contract(
      tokenAddress,
      ERC20_ABI,
      withSigner ? this.signer : this.provider
    );
  }

  async getUserAddress() {
    return await this.signer.getAddress();
  }

  async getTokenMetadata(tokenAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    const [decimals, symbol] = await Promise.all([
      token.decimals(),
      token.symbol()
    ]);
    return { decimals, symbol };
  }

  async getBalance(tokenAddress, userAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    return await token.balanceOf(userAddress);
  }

  async getAllowance(tokenAddress, owner, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    return await token.allowance(owner, spender);
  }

  async approveMax(tokenAddress, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, true);
    const tx = await token.approve(spender, MAX_UINT256);
    const receipt = await tx.wait();
    return { tx, receipt };
  }

  async ensureApproval(tokenAddress, requiredAmount, ownerAddress, spender = this.routerAddress) {
    const allowance = await this.getAllowance(tokenAddress, ownerAddress, spender);
    if (allowance >= requiredAmount) {
      return { approved: false, allowance };
    }
    const approval = await this.approveMax(tokenAddress, spender);
    const updatedAllowance = await this.getAllowance(tokenAddress, ownerAddress, spender);
    return {
      approved: true,
      allowanceBefore: allowance,
      allowanceAfter: updatedAllowance,
      approvalTx: approval.tx,
      approvalReceipt: approval.receipt
    };
  }

  async getQuote(amountIn, path) {
    if (!Array.isArray(path) || path.length < 2) {
      throw new Error("path must contain at least two token addresses");
    }
    return await this.router.getAmountsOut(amountIn, path);
  }

  calculateAmountOutMin(amountOutQuoted, slippageBps = this.defaultSlippageBps) {
    const bpsDenominator = 10000n;
    const quoted = BigInt(amountOutQuoted.toString());
    const min = (quoted * (bpsDenominator - BigInt(slippageBps))) / bpsDenominator;
    return min;
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    amountOutMin,
    path,
    to,
    deadlineSeconds = this.defaultDeadlineSeconds,
    autoApprove = true
  }) {
    const userAddress = to || (await this.getUserAddress());
    const swapPath = path || [tokenIn, tokenOut];

    if (!tokenIn || !tokenOut) throw new Error("tokenIn and tokenOut are required");
    if (!amountIn) throw new Error("amountIn is required");
    if (!Array.isArray(swapPath) || swapPath.length < 2) {
      throw new Error("path must contain at least two token addresses");
    }

    const balance = await this.getBalance(tokenIn, userAddress);
    if (balance < amountIn) {
      throw new Error("insufficient token balance");
    }

    let approvalResult = null;
    if (autoApprove) {
      approvalResult = await this.ensureApproval(tokenIn, amountIn, userAddress, this.routerAddress);
    }

    const deadline = Math.floor(Date.now() / 1000) + deadlineSeconds;
    const tx = await this.router.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      swapPath,
      userAddress,
      deadline
    );
    const receipt = await tx.wait();

    return {
      approval: approvalResult,
      swapTx: tx,
      swapReceipt: receipt
    };
  }

  async quoteAndSwap({
    tokenIn,
    tokenOut,
    amountIn,
    path,
    slippageBps = this.defaultSlippageBps,
    to,
    deadlineSeconds = this.defaultDeadlineSeconds,
    autoApprove = true
  }) {
    const swapPath = path || [tokenIn, tokenOut];
    const amounts = await this.getQuote(amountIn, swapPath);
    const quotedAmountOut = amounts[amounts.length - 1];
    const amountOutMin = this.calculateAmountOutMin(quotedAmountOut, slippageBps);

    const result = await this.swapExactTokensForTokens({
      tokenIn,
      tokenOut,
      amountIn,
      amountOutMin,
      path: swapPath,
      to,
      deadlineSeconds,
      autoApprove
    });

    return {
      quote: {
        path: swapPath,
        amounts,
        quotedAmountOut,
        amountOutMin,
        slippageBps
      },
      ...result
    };
  }

  parseUnits(value, decimals) {
    return ethers.parseUnits(value, decimals);
  }

  formatUnits(value, decimals) {
    return ethers.formatUnits(value, decimals);
  }
}

export async function createBrowserSwapDApp({
  routerAddress,
  defaultSlippageBps,
  defaultDeadlineSeconds
}) {
  if (typeof window === "undefined" || !window.ethereum) {
    throw new Error("No injected wallet found");
  }

  const provider = new ethers.BrowserProvider(window.ethereum);
  await provider.send("eth_requestAccounts", []);
  const signer = await provider.getSigner();

  return new TokenSwapDApp({
    provider,
    signer,
    routerAddress,
    defaultSlippageBps,
    defaultDeadlineSeconds
  });
}

export async function exampleUsage() {
  const ROUTER_ADDRESS = "0xYourRouterAddress";
  const TOKEN_IN = "0xYourTokenInAddress";
  const TOKEN_OUT = "0xYourTokenOutAddress";

  const app = await createBrowserSwapDApp({
    routerAddress: ROUTER_ADDRESS
  });

  const { decimals: inDecimals } = await app.getTokenMetadata(TOKEN_IN);
  const amountIn = app.parseUnits("1.0", inDecimals);

  const result = await app.quoteAndSwap({
    tokenIn: TOKEN_IN,
    tokenOut: TOKEN_OUT,
    amountIn,
    slippageBps: 100,
    autoApprove: true
  });

  return result;
}